 20→
 21→  const {
 22→    pointsQuantity,
 23→    isLoadingBalance,
 24→    isLoadingParameterization,
 25→    isErrorBalance,
 26→    isErrorParameterization,
 27→    requestParameterization,
 28→    requestPointsProducts,
