 1→import { eventServerResponse } from '~/constants/functions';
 2→import { useRootStore } from '~/store';
 3→import { pointsProductsApi } from '../api';
 4→import { ANALYTICS_EVENTS } from '../constants';
 5→import { PointsProductsStatus } from '../models';
 6→import {
 7→  extractConversionFactor,
 8→  findInvoiceProduct,
 9→  mapPointsProductsResponse,
10→} from '../repository';
11→import { getParticipantIdFromToken } from '../utils/participantId';
12→
13→function shouldFetchProducts(): boolean {
14→  const { pointsProducts } = useRootStore.getState();
15→  return pointsProducts.status !== PointsProductsStatus.LOADING;
16→}
17→
18→export async function getPointsProducts(): Promise<void> {
19→  if (!shouldFetchProducts()) {
20→    return;
21→  }
22→
23→  const { pointsProductsActions, parameterPointsProgramActions } =
24→    useRootStore.getState();
25→
26→  try {
27→    pointsProductsActions.setStatus(PointsProductsStatus.LOADING);
28→
29→    const participantId = await getParticipantIdFromToken();
30→    const response = await pointsProductsApi.getProducts(participantId);
31→
32→    const returnCode =
33→      response?.status?.returnCode ?? response?.status?.codigoRetorno ?? 0;
34→
35→    if (returnCode === 0) {
36→      eventServerResponse(ANALYTICS_EVENTS.PRODUCTS_SUCCESS);
37→
38→      const products = mapPointsProductsResponse(response);
39→      pointsProductsActions.setProducts(products);
40→
41→      const conversionFactor = extractConversionFactor(products);
42→      parameterPointsProgramActions.setConversionFactor(conversionFactor);
43→
44→      const invoiceProduct = findInvoiceProduct(products);
45→      if (invoiceProduct?.conversionFactor) {
46→        parameterPointsProgramActions.setConversionFactor(
47→          invoiceProduct.conversionFactor,
48→        );
49→      }
50→
51→      eventServerResponse(ANALYTICS_EVENTS.PRODUCTS_SUCCESS);
52→    } else {
53→      eventServerResponse(ANALYTICS_EVENTS.PRODUCTS_ERROR);
54→      pointsProductsActions.setError(response?.status?.message);
55→      pointsProductsActions.setStatus(PointsProductsStatus.ERROR);
56→      eventServerResponse(ANALYTICS_EVENTS.PRODUCTS_ERROR);
57→    }
58→  } catch (_error) {
59→    eventServerResponse(ANALYTICS_EVENTS.PRODUCTS_ERROR);
60→    pointsProductsActions.setError('Erro ao carregar produtos');
61→    pointsProductsActions.setStatus(PointsProductsStatus.ERROR);
62→  }
63→}
