31→function handleOrderDetailError(): void {
32→  const { orderDetailActions } = useRootStore.getState();
33→  orderDetailActions.setOrderDetailStatus(OrderDetailStatus.ERROR);
34→  eventServerResponse(ANALYTICS_EVENTS.ORDER_DETAIL_ERROR);
