37→export async function getOrderDetail(
38→  payload: GetOrderDetailPayload,
39→): Promise<void> {
40→  const { orderDetailActions, orderDetail } = useRootStore.getState();
41→
42→  const isDifferentTransaction =
43→    orderDetail.transactionId !== payload.transactionId;
44→  const isAlreadyLoading = orderDetail.status === OrderDetailStatus.LOADING;
45→
46→  if (isAlreadyLoading && !isDifferentTransaction) {
47→    return;
48→  }
49→
50→  if (isDifferentTransaction) {
51→    orderDetailActions.reset();
52→  }
53→
54→  orderDetailActions.setOrderDetailStatus(OrderDetailStatus.LOADING);
55→
56→  try {
57→    const participantId =
58→      payload?.participantId ?? (await getParticipantIdFromToken());
59→
60→    if (!participantId) {
61→      handleOrderDetailError();
62→      return;
63→    }
64→
65→    const requestPayload: OrderDetailRequestDto = {
66→      transactionId: payload.transactionId,
67→      participantId,
68→    };
69→
70→    const response = await getOrderDetailApi(requestPayload);
71→    const orderDetailData = getOrderDetailFromResponse(response);
72→
73→    if (orderDetailData) {
74→      handleOrderDetailSuccess(orderDetailData, payload.transactionId);
75→      return;
76→    }
77→
78→    handleOrderDetailError();
79→  } catch {
80→    handleOrderDetailError();
81→  }
82→}
